from modal import Image, App, method

base_image = Image.debian_slim().pip_install("openai")

@app.cls(image=base_image, cpu=2, timeout=600)
class IsolatedToolExecutor:
    def __init__(self):
        self.rollout_id = None

    @method()
    def execute_shell(self, rollout_id: str, command: str):
        # Safe: this VM is dedicated to this rollout
        result = subprocess.run(
            command, shell=True, capture_output=True, text=True
        )
        return {
            "stdout": result.stdout,
            "returncode": result.returncode
        }
